import requests

def test_post_api_auth_login_with_valid_credentials():
    base_url = "http://localhost:8000"
    url = f"{base_url}/api/auth/login"
    headers = {
        "Content-Type": "application/json"
    }
    # Valid credentials (email and password) must be known or assumed for the test.
    # As the PRD doesn't specify real credentials, using placeholder valid ones.
    payload = {
        "email": "validuser@example.com",
        "password": "validpassword123"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=30)
        response.raise_for_status()
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200, f"Expected status code 200, got {response.status_code}"

    # Expecting a token in the response JSON, key name not specified; try common keys
    json_resp = response.json()
    token = None
    # typical Laravel Sanctum returns token as "token" or "access_token"
    if "token" in json_resp and isinstance(json_resp["token"], str) and json_resp["token"]:
        token = json_resp["token"]
    elif "access_token" in json_resp and isinstance(json_resp["access_token"], str) and json_resp["access_token"]:
        token = json_resp["access_token"]
    elif "data" in json_resp and isinstance(json_resp["data"], dict):
        # Sometimes token inside data object
        data = json_resp["data"]
        if "token" in data and isinstance(data["token"], str) and data["token"]:
            token = data["token"]
        elif "access_token" in data and isinstance(data["access_token"], str) and data["access_token"]:
            token = data["access_token"]

    assert token is not None, "Sanctum token not found in response"

test_post_api_auth_login_with_valid_credentials()

import requests

base_url = "http://localhost:8000"
timeout_seconds = 30


def test_get_api_classes_with_valid_token():
    # First, login to obtain token
    login_payload = {
        "email": "admin@example.com",
        "password": "password"
    }
    try:
        login_resp = requests.post(f"{base_url}/api/auth/login", json=login_payload, timeout=timeout_seconds)
    except requests.RequestException as e:
        assert False, f"Request to POST /api/auth/login failed due to exception: {e}"

    assert login_resp.status_code == 200, f"Expected status code 200 from login but got {login_resp.status_code}"

    try:
        token = login_resp.json()
    except ValueError:
        assert False, "Login response content is not valid JSON"

    # Assuming the token is directly returned as a string or dict with token key
    if isinstance(token, dict) and "token" in token:
        token_value = token["token"]
    elif isinstance(token, str):
        token_value = token
    else:
        # If response format is unexpected, assert false
        assert False, f"Unexpected token format in login response: {token}"

    headers = {
        "Authorization": f"Bearer {token_value}"
    }

    try:
        response = requests.get(f"{base_url}/api/classes", headers=headers, timeout=timeout_seconds)
    except requests.RequestException as e:
        assert False, f"Request to GET /api/classes failed due to exception: {e}"

    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"

    try:
        classes_list = response.json()
    except ValueError:
        assert False, "Response content is not valid JSON"

    assert isinstance(classes_list, list), "Response JSON is not a list of classes"


test_get_api_classes_with_valid_token()
